-- API Mistral (hébergée) : retrait de « tout tourne en local », cadrage IA européenne + recherche auto-hébergée.
BEGIN;

UPDATE projects SET architecture = 'Le moteur collecte des documents de référence, les découpe et les indexe. Le sens du texte est capté par des embeddings open source (bge-m3) stockés dans une base vectorielle PostgreSQL/pgvector. La recherche combine mots-clés et sens, fusionnés pour ne rater ni un terme précis comme « créatine » ni une formulation différente. La génération de la réponse finale est confiée à l''API Mistral (IA européenne).', results = 'Bora prouve que je sais concevoir une IA fiable et traçable : elle s''appuie sur de vraies sources plutôt que d''halluciner, et chaque réponse reste rattachée à son origine. Le pipeline fonctionne de bout en bout — base de connaissances auto-hébergée pour la recherche, puis génération via l''API Mistral (IA européenne). Un vrai gage de maîtrise, de qualité et de traçabilité.', features = ARRAY['Réponses appuyées sur de vraies sources reconnues (santé, nutrition, science)', 'Retrouve l''information la plus pertinente pour chaque question posée', 'Tient compte du contexte de l''utilisateur pour mieux cibler la réponse', 'Recherche hybride : comprend le sens ET retrouve les termes techniques exacts', 'Chaque réponse reste rattachée à sa source d''origine', 'Génération via l''API Mistral — une IA européenne, plutôt qu''un modèle propriétaire américain', 'Brique IA de l''écosystème JoyTrain (app + moteur Bora + site vitrine)']::text[], updated_at = now() WHERE slug = 'bora-rag-joytrain';

UPDATE projects SET features = ARRAY['Suivi d''entraînement complet : exercices, programmes, cardio et records personnels', 'Coach IA conversationnel « Bora » propulsé par l''API Mistral (IA européenne), qui répond et génère des séances sur mesure', 'Scan d''un repas par photo pour estimer automatiquement les apports', 'Journal nutrition adossé à une vraie base alimentaire et ses macros', 'Couche sociale : amis, posts, messagerie et notifications en temps réel', 'Mode hors-ligne : on enregistre ses séances sans réseau, tout se synchronise ensuite', 'Graphiques de progression et atlas musculaire interactif', 'Prête pour les stores (TestFlight iOS et Google Play)']::text[], updated_at = now() WHERE slug = 'joytrain';

COMMIT;
